defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset
  
  schema "users" do
    field :email, :string
    field :name, :string
    field :password, :string, virtual: true
    field :password_hash, :string
    field :role, :string, default: "user"
    field :is_admin, :boolean, default: false
    field :permissions, {:array, :string}, default: []
    field :status, :string, default: "active"
    field :verified, :boolean, default: false
    field :phone, :string
    field :bio, :string
    field :avatar_url, :string
    
    timestamps()
  end
  
  def changeset(user, attrs) do
    user
    |> cast(attrs, [:email, :name, :password, :role, :is_admin, :permissions, :status, :verified, :phone, :bio, :avatar_url])
    |> validate_required([:email])
    |> validate_format(:email, ~r/@/)
    |> validate_length(:password, min: 8, max: 100)
    |> unique_constraint(:email)
    |> hash_password()
  end
  
  defp hash_password(changeset) do
    case get_change(changeset, :password) do
      nil -> changeset
      password -> put_change(changeset, :password_hash, Bcrypt.hash_pwd_salt(password))
    end
  end
end

defmodule MyAppWeb.Plugs.AuthenticateUser do
  import Plug.Conn
  import Phoenix.Controller
  
  alias MyApp.Accounts
  alias MyApp.Repo
  
  def init(opts), do: opts
  
  def call(conn, _opts) do
    with ["Bearer " <> token] <- get_req_header(conn, "authorization"),
         {:ok, user_id} <- verify_token(token),
         user when not is_nil(user) <- Repo.get(MyApp.Accounts.User, user_id) do
      assign(conn, :current_user, user)
    else
      _ ->
        conn
        |> put_status(:unauthorized)
        |> json(%{error: "Invalid or missing authentication token"})
        |> halt()
    end
  end
  
  defp verify_token(token) do
    case Phoenix.Token.verify(MyAppWeb.Endpoint, "user auth", token, max_age: 86400) do
      {:ok, user_id} -> {:ok, user_id}
      {:error, _} -> :error
    end
  end
end